media_type.script:
var params = JSON.parse(value);
var url = params.webhook_url;
var type = params.webhook_type;
var subject = params.subject;
var message = params.message;
var severity = params.severity;

if (!url) {
    throw 'Webhook URL not configured. Set {$ALERT.WEBHOOK.URL} macro.';
}

var payload;

switch (type) {
    case 'discord':
        var color = severity === 'Disaster' ? 16711680 : severity === 'High' ? 16744448 : 16776960;
        payload = JSON.stringify({
            embeds: [{
                title: '\u26a0\ufe0f ' + subject,
                description: message,
                color: color,
                footer: { text: 'Zabbix Alert \u2014 rAthena Server' },
                timestamp: new Date().toISOString()
            }]
        });
        break;
    case 'telegram':
        payload = JSON.stringify({
            chat_id: params.telegram_chat_id || '',
            text: '\u26a0\ufe0f *' + subject + '*\n\n' + message,
            parse_mode: 'Markdown'
        });
        break;
    case 'slack':
        var emoji = severity === 'Disaster' ? '\ud83d\udd34' : severity === 'High' ? '\ud83d\udfe0' : '\ud83d\udfe1';
        payload = JSON.stringify({
            blocks: [{
                type: 'section',
                text: {
                    type: 'mrkdwn',
                    text: emoji + ' *' + subject + '*\n' + message
                }
            }]
        });
        break;
    default:
        throw 'Unknown webhook type: ' + type + '. Supported: discord, telegram, slack';
}

var req = new HttpRequest();
req.addHeader('Content-Type: application/json');
var resp = req.post(url, payload);

if (req.getStatus() < 200 || req.getStatus() >= 300) {
    throw 'Webhook failed with status ' + req.getStatus() + ': ' + resp;
}

return 'OK';
